// <auto-generated>
// EventSource (Server-Sent Events) interop for real-time object notifications.
// Replaces the SignalR client: it opens the API server's notification stream and
// forwards each "PropertyUpdated" event to the calling Blazor component's
// [JSInvokable] OnPropertyUpdated method. The native EventSource reconnects on
// its own, so there is no manual retry logic here.
// </auto-generated>
window.jumpstartSse = {
    connect: function (url, dotNetRef) {
        const source = new EventSource(url);

        source.addEventListener("PropertyUpdated", function (e) {
            dotNetRef.invokeMethodAsync("OnPropertyUpdated", e.data);
        });

        source.onerror = function () {
            // EventSource automatically reconnects with a backoff; nothing to do.
        };

        // Returned to .NET as an IJSObjectReference so the component can close
        // the stream on dispose.
        return {
            close: function () {
                source.close();
            }
        };
    }
};
